def _calculate(a, b, op):
    """Calculates the result of an operation on two numbers."""
    if op == 'add':
        return a + b
    elif op == 'sub':
        return a - b
    elif op == 'mul':
        return a * b
    elif op == 'div':
        if b == 0:
            return None  # Handle division by zero
        return a / b
    elif op == 'pow':
        return math.pow(a, b)
    else:
